+fn make_output(name: &str) -> ExpectedOutput {
+    ExpectedOutput {
+        name: name.to_string(),
+        expected_hash: Some(ContentHash::compute(name.as_bytes())),
+        exact_match: true,
+        tolerance_millionths: 0,
+    }
